import { getContext } from './context'
import { KeaPlugin, PluginEvents } from '../types'

const reservedKeys = {
  key: true,
  path: true,
  pathString: true,
  props: true,
  inputs: true,
  wrapper: true,
  wrap: true,
  build: true,
  mount: true,
